import{_ as o,o as t,c as a,ag as r}from"./chunks/framework.CAXxHpAX.js";const m=JSON.parse('{"title":"Robot Control","description":"","frontmatter":{},"headers":[],"relativePath":"projects/robot-control.md","filePath":"projects/robot-control.md","lastUpdated":null}'),i={name:"projects/robot-control.md"};function n(l,e,s,c,d,h){return t(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="robot-control" tabindex="-1">Robot Control <a class="header-anchor" href="#robot-control" aria-label="Permalink to &quot;Robot Control&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p><strong>Robot Control</strong> summarizes a multi-phase effort to bring a manipulation arm from first motion to repeatable pick-and-place under conservative safety envelopes. Work spanned low-level torque commanding, outer-loop Cartesian behavior, and contact-aware recovery.</p><h2 id="motivation" tabindex="-1">Motivation <a class="header-anchor" href="#motivation" aria-label="Permalink to &quot;Motivation&quot;">​</a></h2><p>Demonstrations are easy; <strong>repeatable</strong> behavior under latency and modeling error is the bar for useful autonomy. This project chased determinism first, cleverness second.</p><h2 id="technical-scope" tabindex="-1">Technical Scope <a class="header-anchor" href="#technical-scope" aria-label="Permalink to &quot;Technical Scope&quot;">​</a></h2><ul><li>Inner-loop torque with saturation and thermal guardrails</li><li>Outer-loop impedance with wrench limits and guarded moves near humans</li><li>Logging sufficient to align video with <strong>500 Hz</strong> control timelines for post hoc review</li></ul><h2 id="what-i-learned" tabindex="-1">What I Learned <a class="header-anchor" href="#what-i-learned" aria-label="Permalink to &quot;What I Learned&quot;">​</a></h2><ul><li>Treat <strong>message age</strong> as a first-class state; without it, you optimize the wrong subsystem.</li><li>Friction identification is unglamorous and disproportionately valuable for contact transitions.</li></ul><h2 id="related-notes" tabindex="-1">Related Notes <a class="header-anchor" href="#related-notes" aria-label="Permalink to &quot;Related Notes&quot;">​</a></h2><ul><li><a href="/articles/robotics-control/">Robotics Control articles</a></li><li><a href="/tech-log/2026/2026-w18.html">2026-W18 Tech Log</a></li></ul>',11)])])}const p=o(i,[["render",n]]);export{m as __pageData,p as default};
